class Engine {
    void start() {
        System.out.println("Engine starting...");
    }
}

class Car {
    // Car HAS-A Engine
    private Engine engine = new Engine(); 

    void move() {
        engine.start(); // Delegates work to the component
        System.out.println("Car is moving");
    }
}

// Usage
Car myCar = new Car();
myCar.move();

interface Engine {
    void consumeFuel();
}

class GasEngine implements Engine {
    public void consumeFuel() { System.out.println("Burning gasoline..."); }
}

class ElectricEngine implements Engine {
    public void consumeFuel() { System.out.println("Using battery power..."); }
}

class HybridCar {
    private Engine engine; // Composition: refers to the interface

    public void setEngine(Engine newEngine) {
        this.engine = newEngine; // Swapping at runtime!
    }

    public void drive() {
        engine.consumeFuel();
    }
}

public class Main {
    public static void main(String[] args) {
        HybridCar myCar = new HybridCar();

        // Start with Gas
        myCar.setEngine(new GasEngine());
        myCar.drive(); // Output: Burning gasoline...

        // SWAP AT RUNTIME: Now it's an Electric car
        myCar.setEngine(new ElectricEngine());
        myCar.drive(); // Output: Using battery power...
    }
}

class GasolineEngine {
    void start() { System.out.println("Gas engine started"); }
}

class Car {
    // Car is hardcoded to only work with GasolineEngine
    private GasolineEngine engine = new GasolineEngine(); 

    void drive() {
        engine.start();
        System.out.println("Car is moving");
    }
}

interface Engine {
    void start();
}

class GasolineEngine implements Engine {
    public void start() { System.out.println("Gas engine started"); }
}

class ElectricEngine implements Engine {
    public void start() { System.out.println("Electric motor humming"); }
}

class Car {
    private Engine engine;

    // The specific engine is passed in (Injected)
    Car(Engine engine) {
        this.engine = engine;
    }

    void drive() {
        engine.start();
        System.out.println("Car is moving");
    }
}

